// src/config/schema.ts
import { z } from "zod";
var TDDConfigSchema = z.object({
  // =========================================
  // AGENT MODEL OVERRIDES
  // =========================================
  models: z.object({
    /**
     * Model for Actor agent (implements tasks)
     * If not specified, uses the current session model
     */
    actor: z.string().optional(),
    /**
     * Model for Critic agent (validates tasks)
     * If not specified, uses the current session model
     */
    critic: z.string().optional(),
    /**
     * Model for Orchestrator agent (coordinates workflow)
     * If not specified, uses the current session model
     */
    orchestrator: z.string().optional(),
    /**
     * Model for Architect agent (generates documents)
     * If not specified, uses the current session model
     */
    architect: z.string().optional()
  }).default({}),
  // =========================================
  // WORKFLOW SETTINGS
  // =========================================
  workflow: z.object({
    /** Maximum retry attempts before escalating */
    maxRetries: z.number().min(1).max(10).default(3),
    /** Automatically run Critic validation after Actor completes */
    autoValidate: z.boolean().default(true),
    /** Test command to run (supports npm, pnpm, yarn, bun) */
    testCommand: z.string().default("npm test"),
    /** Directory for task files */
    tasksDir: z.string().default("tasks"),
    /** Directory for context files */
    contextDir: z.string().default(".context"),
    /** Directory for TDD state */
    stateDir: z.string().default(".tdd")
  }).default({}),
  // =========================================
  // DOCUMENT GENERATION SETTINGS
  // =========================================
  documents: z.object({
    /** Minimum lines for PRD */
    minPrdLines: z.number().min(50).default(300),
    /** Minimum lines for technical spec (MUST include ALL code) */
    minSpecLines: z.number().min(100).default(1200),
    /** Minimum lines for test spec */
    minTestLines: z.number().min(50).default(500),
    /** Minimum lines for agent spec */
    minAgentSpecLines: z.number().min(50).default(150),
    /** Minimum lines for tasks breakdown */
    minTasksLines: z.number().min(100).default(800)
  }).default({}),
  // =========================================
  // FEATURE FLAGS
  // =========================================
  features: z.object({
    /** Enable Architect agent for document generation */
    architectAgent: z.boolean().default(true),
    /** Auto-save TDD state on session end */
    autoSaveState: z.boolean().default(true),
    /** Track test command results */
    testTracking: z.boolean().default(true),
    /** Inject TDD context into session compaction */
    compactionContext: z.boolean().default(true)
  }).default({}),
  // =========================================
  // AGENT PROMPT CUSTOMIZATION
  // =========================================
  prompts: z.object({
    /** Additional instructions appended to Actor prompt */
    actorAppend: z.string().optional(),
    /** Additional instructions appended to Critic prompt */
    criticAppend: z.string().optional(),
    /** Additional instructions appended to Orchestrator prompt */
    orchestratorAppend: z.string().optional(),
    /** Additional instructions appended to Architect prompt */
    architectAppend: z.string().optional()
  }).default({})
});
var defaultConfig = TDDConfigSchema.parse({});

// src/config/loader.ts
async function loadConfig(projectDir) {
  let dirPath;
  if (typeof projectDir === "string") {
    dirPath = projectDir;
  } else if (projectDir && typeof projectDir === "object" && projectDir.path) {
    dirPath = projectDir.path;
  } else if (projectDir && typeof projectDir === "object" && projectDir.toString) {
    dirPath = projectDir.toString();
  } else {
    dirPath = process.cwd();
  }
  const configPaths = [
    join(dirPath, "opencode-tdd.json"),
    join(dirPath, ".opencode", "opencode-tdd.json"),
    join(process.env.HOME || "~", ".config", "opencode", "opencode-tdd.json")
  ];
  for (const configPath of configPaths) {
    try {
      const content = await readFile(configPath, "utf-8");
      const rawConfig = JSON.parse(content);
      const config = TDDConfigSchema.parse(rawConfig);
      return config;
    } catch {
      continue;
    }
  }
  return defaultConfig;
}

// src/index.ts
var TDDPlugin = async (ctx) => {
  const { client, $, directory, worktree } = ctx;
  const config = await loadConfig(directory);
  return {
    // =========================================
    // CUSTOM TOOLS
    // =========================================
    tool: {
      tdd_init: tddInitTool($, directory),
      tdd_status: tddStatusTool($, directory),
      tdd_next: tddNextTool($, directory),
      tdd_state: tddStateTool($, directory)
    },
    // =========================================
    // AGENT CONFIGURATION INJECTION
    // =========================================
    config: async (openCodeConfig) => {
      openCodeConfig.agent = {
        ...openCodeConfig.agent,
        actor: actorAgent(config),
        critic: criticAgent(config),
        orchestrator: orchestratorAgent(config),
        architect: architectAgent(config)
      };
    },
    // =========================================
    // EVENT HOOKS
    // =========================================
    event: async ({ event }) => {
      if (config.features?.testTracking !== false) {
        await createTestTrackerHook($, directory)(event);
      }
      if (config.features?.autoSaveState !== false) {
        await createStatePersistHook($, directory)(event);
      }
    },
    // =========================================
    // SESSION COMPACTION HOOK
    // =========================================
    "experimental.session.compacting": async (input, output) => {
      try {
        const stateJson = await $`cat ${directory}/.tdd/state.json 2>/dev/null`.text();
        const state = JSON.parse(stateJson);
        output.context.push(`
## TDD Workflow Context (Preserved Across Compaction)

**Current Phase**: ${state.workflow_phase || "unknown"}
**Current Task**: ${state.current_task || "none"}
**Progress**: ${state.completed_tasks?.length || 0}/${state.total_tasks || 0} tasks completed
**Attempt**: ${state.current_attempt || 1}

### Completed Tasks
${state.completed_tasks?.map((t) => `- \u2705 ${t}`).join("\n") || "None yet"}

### Last Critic Feedback
${state.last_critic_feedback || "None"}

### Important
- Actor and Critic agents use FRESH context per invocation
- Task files in tasks/ directory contain full requirements
- State is tracked in .tdd/state.json
`);
      } catch {
      }
    },
    // =========================================
    // TOOL EXECUTION HOOKS
    // =========================================
    "tool.execute.after": async (input, output) => {
    }
  };
};
var index_default = TDDPlugin;
